import typing as t
from functools import cmp_to_key

class SortedDict(t.MutableMapping):
    def __init__(self, initial_items: t.Optional[t.List[t.Tuple]] = None, key: t.Callable = None):
        self._items = initial_items.copy() if initial_items is not None else []
        self._key = key
    def __getitem__(self, key):
        for k, v in sorted(self._items, key=self._key if self._key else lambda k: k):
            if k == key:
                return v
        raise KeyError(key)
    def __setitem__(self, key, value):
        self._items.append((key, value))
        self._items.sort(key=self._key)
    def __delitem__(self, key):
        for i, (k, v) in enumerate(self._items):
            if k == key:
                del self._items[i]
                return
        raise KeyError(key)
    def keys(self) -> t.KeysView:
        return (k for k, _ in self._items)
    def values(self) -> t.ValuesView:
        return (v for _, v in self._items)
    def items(self) -> t.ItemsView:
        return self._items

