def calculate_subtotal(item):
   return (item['price'] * 1.1) * item['quantity'] - (item['price'] * item['discount']) * item['quantity']

def calculate_order_total(order):
   return sum([
      calculate_subtotal(item)
      for item in order
      if item['quantity'] > 0
   ])

