import os

class DataProcessor:
    def __init__(self):
        pass

    def load_data(self, file_path):
        try:
            with open(file_path, 'r') as file:
                data = [row.strip().split(',') for row in file.readlines()]
                return [{'name': row[0], 'age': int(row[1]), 'income': round(float(row[2]), 2)} for row in data]
        except FileNotFoundError:
            return {'status': 'error', 'message': 'Input file not found'}

    def filter_data(self, data, threshold):
        return [row for row in data if int(row['age']) > threshold]

    def save_data(self, output_file, data):
        with open(output_file, 'w') as file:
            file.write(','.join([row['name'] for row in data]))

    def process_data(self, input_file, output_file, threshold):
        data = self.load_data(input_file)
        if not data:
            return {'status': 'error', 'message': 'No data found'}
        filtered_data = self.filter_data(data, threshold)
        self.save_data(output_file, filtered_data)
        return {'status': 'success', 'message': 'Data processed successfully'}

