from dataclasses import dataclass
from typing import List

@dataclass
class StoreItem:
    initial_price: float
    quantity: int

@dataclass
class Order:
    total_price: float

@dataclass
class Sale:
    sale_amount: float

def calculate_inventory_total(store_data: List[StoreItem], orders_data: List[Order], sales_data: List[Sale]):
    total_inventory = 0
    for item in store_data:
        total_inventory += item.initial_price * item.quantity
    for sale in sales_data:
        total_inventory -= sale.sale_amount
    for order in orders_data:
        total_inventory += order.total_price
    return total_inventory

def calculate_item_profit(store_data: List[StoreItem], orders_data: List[Order], sales_data: List[Sale]):
    total_profit = 0
    for item in store_data:
        total_profit += item.initial_price * item.quantity * 0.2
    for order in orders_data:
        total_profit -= order.total_price * 0.1
    for sale in sales_data:
        total_profit += sale.sale_amount * 0.3
    return total_profit

