class ResultsSaver:
    def __init__(self, db_name):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()
    def save_results(self, total, count):
        query = 'INSERT INTO results (total, count) VALUES (?, ?)'
