calculate_area_of_complex_shape.code:
def calculate_area_of_complex_shape(polygon_points):
  def distance(p1, p2):
    return ((p1[0] - p2[0]) ** 2 + (p1[1] - p2[1]) ** 2) ** 0.5
  n = len(polygon_points)
  area = 0
  for i in range(n):
    p1 = polygon_points[i]
    p2 = polygon_points[(i + 1) % n]
    area += p1[0] * p2[1] - p2[0] * p1[1]
  return abs(area) / 2

