    # Initialize result object
    result = {
        'employees': [],
        'taxes': {},
        'holidays': {}
    }
    # Calculate taxes for each employee
    for employee in all_employees_data:
        if employee['status'] != 'active':
            continue
        if employee['holiday_status'] != 'active':
            continue
        employee_tax = calculate_tax(employee, tax_rates)
        result['employees'].append({'name': employee['name'], 'gross_salary': employee['gross_salary'], 'tax': employee_tax})
        result['taxes'][employee['name']] = employee_tax
        for holiday in holiday_data:
            if holiday['date'] == employee['holiday_date']:
                result['holidays'][holiday['name']] = holiday['amount']
    # Return the result object
    return result

