import re from typing import List, Dict
def load_file(file_name: str) -> List[str]:
    with open(file_name, 'r') as f:
        return f.readlines()

def extract_word_frequency(lines: List[str]) -> List[Dict[str, str]]:
    result = []
    for line in lines:
        words = re.findall(r' w+ ', line)
        result.append({'word': words[0], 'frequency': str(len(words))})
    return result

def save_result(result: List[Dict[str, str]], output_file: str) -> None:
    with open(output_file, 'w') as f:
        f.write(str(result))

def calculate_statistics(input_file: str, output_file: str) -> List[Dict[str, str]]:
    lines = load_file(input_file)
    result = extract_word_frequency(lines)
    save_result(result, output_file)
    return result

