def calculate_subtotal(order): 
    return sum(item['price'] * item['quantity'] for item in order['items'])

def calculate_discount(customer): 
    return customer['loyalty_program']['discount'] if customer['loyalty_program'] else 0

def calculate_tax(order): 
    if order['location']['country'] == 'US': return order['items'][0]['price'] * 0.08
    else: return 0

def calculate_shipping(order): 
    weight = sum(item['weight'] * item['quantity'] for item in order['items'])
    if weight > 10: return 10
    elif weight > 5: return 5
    else: return 0

def calculate_total(customer, order): 
    subtotal = calculate_subtotal(order)
    discount = calculate_discount(customer)
    tax = calculate_tax(order)
    shipping = calculate_shipping(order)
    return subtotal - discount + tax + shipping

