def calculate_invoices(invoices, payments):
  outstanding_invoices = invoices.copy()
  for payment in payments:
    for invoice in invoices:
      if invoice['id'] == payment['invoice_id']:
        invoice['total'] -= payment['amount']
      if invoice['total'] <= 0:
        outstanding_invoices.remove(invoice)
  return outstanding_invoices
