def extract_invoice(invoice_id, invoices):
  for invoice in invoices:
    if invoice['id'] == invoice_id:
      return invoice
  return None

def update_invoice(invoice, amount):
  invoice['total'] -= amount
  if invoice['total'] <= 0:
    return None
  return invoice

def calculate_invoices(invoices, payments):
  outstanding_invoices = [invoice.copy() for invoice in invoices]
  for payment in payments:
    updated_invoice = update_invoice(extract_invoice(payment['invoice_id'], invoices), payment['amount'])
    if updated_invoice:
      next((i for i, x in enumerate(outstanding_invoices) if x['id'] == updated_invoice['id']), None)
      outstanding_invoices[next((i for i, x in enumerate(outstanding_invoices) if x['id'] == updated_invoice['id']), None)] = updated_invoice
  return [invoice for invoice in outstanding_invoices if invoice['total'] > 0]
