def calculate_expenses(invoices, rates, taxes, discounts, payment_methods):
    def calculate_invoice_total(invoice, rates, taxes, discounts):
        return invoice['amount'] * rates[invoice['currency']] + invoice['taxes'] * taxes[invoice['tax_rate']] - invoice['discounts'] * discounts[invoice['discount_type']] * invoice['amount']

    def calculate_customer_expenses(invoices, customer_info):
        customer_expenses = 0
        for invoice in invoices:
            if invoice['customer_id'] == customer_info['id']:
                customer_expenses += calculate_invoice_total(invoice, rates, taxes, discounts)
        return customer_expenses

    customer_expenses = 0
    for customer in customer_info:
        customer_expenses += calculate_customer_expenses(invoices, customer)

    return customer_expenses

