def calculate_order_total(order_data):
  tax_rate = 0.08
  subtotal = 0
  for item in order_data:
    subtotal += item['price'] * item['quantity']
  total = subtotal + (subtotal * tax_rate)
  if order_data['discount']:
    total -= order_data['discount']['amount']
  return total

def calculate_subtotal(order_items):
  return sum(item['price'] * item['quantity'] for item in order_items)

def calculate_tax(subtotal):
  return subtotal * 0.08

def apply_discount(subtotal, discount):
  if discount:
    return subtotal - discount['amount']
  else:
    return subtotal

def calculate_order_total(order_data):
  subtotal = calculate_subtotal(order_data['items'])
  tax = calculate_tax(subtotal)
