class Calculator:
    def __init__(self, tax_rate, shipping_cost):
        self.tax_rate = tax_rate
        self.shipping_cost = shipping_cost

    def calculate_subtotal(self, items):
        return sum(item['price'] * item['quantity'] for item in items)

    def calculate_tax(self, subtotal):
        return subtotal * self.tax_rate / 100

    def calculate_grand_total(self, subtotal, tax, shipping_cost):
        return subtotal + tax + shipping_cost

    def calculate_order_summary(self, order_id, customer_name, order_date, items):
        subtotal = self.calculate_subtotal(items)
        tax = self.calculate_tax(subtotal)
        grand_total = self.calculate_grand_total(subtotal, tax, self.shipping_cost)
        return {'id': order_id, 'customer': customer_name, 'date': order_date, 'subtotal': subtotal, 'tax': tax, 'shipping': self.shipping_cost, 'grand_total': grand_total}

