class FileReader:
    def __init__(self, file_name: str):
        self.file_name = file_name

    def read_file(self) -> str:
        try:
            with open(self.file_name, 'r') as file:
                return file.read()
        except FileNotFoundError:
            print(f'File {self.file_name} not found.')
            return ''

    def extract_digits(self, content: str) -> List[int]:
        return [int(digit) for digit in re.findall('\d', content)]

def calculate_sum(numbers: List[int]) -> int:
    return sum(numbers)

def process_data(file_reader: FileReader) -> str:
    content = file_reader.read_file()
    digits = file_reader.extract_digits(content)
    sum_of_digits = calculate_sum(digits)
    return str(sum_of_digits) + '!'

