class StatisticsCalculator:
   def __init__(self, file_name):
      self.file_name = file_name

   def calculate_total_sales(self):
      total_sales = 0
      try:
         with open(self.file_name, 'r') as f:
            for line in f:
               words = line.split()
               if len(words) > 3 and words[0] == 'sales:
                  total_sales += int(words[1])
               else:
                  print(f'Invalid line: {line}')
      except FileNotFoundError:
         print(f'File {self.file_name} not found')
         return None
      return total_sales

   def calculate_total_quantity(self):
      total_quantity = 0
      try:
         with open(self.file_name, 'r') as f:
            for line in f:
               words = line.split()
               if len(words) > 3 and words[0] == 'sales:
                  total_quantity += int(words[2])
               else:
                  print(f'Invalid line: {line}')
      except FileNotFoundError:
         print(f'File {self.file_name} not found')
         return None
      return total_quantity

   def calculate_average_price(self):
      count = 0
      total = 0
      try:
         with open(self.file_name, 'r') as f:
            for line in f:
               words = line.split()
               if len(words) > 3 and words[0] == 'sales:
                  total += int(words[2])
                  count += 1
               else:
                  print(f'Invalid line: {line}')
      except FileNotFoundError:
         print(f'File {self.file_name} not found')
         return None
      try:
         return total / count
      except ZeroDivisionError:
         return 0

   def calculate_statistics(self):
      total_sales = self.calculate_total_sales()
      total_quantity = self.calculate_total_quantity()
      average_price = self.calculate_average_price()
      return {'total_sales': total_sales, 'total_quantity': total_quantity, 'average_price': average_price}

