validate_credit_card.code:
def validate_credit_card(card_number):
  def digits_of(n):
    return [int(d) for d in str(n)]
  nums = digits_of(card_number)
  odd_digits = nums[-1::-2]
  even_digits = nums[-2::-2]
  checksum = 0
  for d in odd_digits:
    checksum += d
  for d in even_digits:
    checksum += sum(digits_of(d*2))
  return checksum % 10 == 0

def validate_credit_card(card_number):
  def sum_of_digits(n):
    return sum(int(digit) for digit in str(n))
  return not sum_of_digits(card_number[:-1]) + sum_of_digits(card_number[-1]) % 10 == 0

