from typing import Dict
from dataclasses import dataclass

@dataclass
class Product:
    id: str
    price: float
    tax_rate: float

@dataclass
class Invoice:
    product_id: str
    quantity: int

class DiscountCalculator:
    def __init__(self, tax_rates: Dict[str, float]):
        self.tax_rates = tax_rates

    def calculate_discounts(self, products: Dict[str, Product], invoice: Invoice):
        discounts = {}
        for product in products.values():
            if product.id in invoice.product_id:
                discount = product.price * (product.tax_rate / 100)
                discounts[product.id] = discount
        return discounts

class PriceUpdater:
    def __init__(self, discounts: Dict[str, float]):
        self.discounts = discounts

    def update_prices(self, products: Dict[str, Product]):
        updated_prices = {}
        for product in products.values():
            updated_price = product.price - self.discounts.get(product.id, 0)
            updated_prices[product.id] = updated_price
        return updated_prices

class TotalCostCalculator:
    def __init__(self, products: Dict[str, Product], invoice: Invoice):
        self.products = products
        self.invoice = invoice

    def calculate_total_cost(self, net_prices: Dict[str, float]):
        total_cost = 0
        for product_id, quantity in self.invoice.__dict__.items():
            price = net_prices[product_id]
            total_cost += quantity * price
        return total_cost

def calculate_discounts_and_update_prices(tax_rates: Dict[str, float], products: Dict[str, Product], invoice: Invoice):
    calculator = DiscountCalculator(tax_rates)
    discounts = calculator.calculate_discounts(products, invoice)
    updater = PriceUpdater(discounts)
    net_prices = updater.update_prices(products)
    calculator_2 = TotalCostCalculator(products, invoice)
    total_cost = calculator_2.calculate_total_cost(net_prices)
    return total_cost

