def calculate_bonus(level, years_of_service, performance_rating, salary):
    bonus_calculators = {
        'senior': lambda x, y, z: 0.1 * x * y * z,
        'junior': lambda x, y, z: 0.05 * x * y * z
    }
    bonus = bonus_calculators[level](salary, years_of_service, performance_rating)
    return bonus

# Example usage
