import pandas as pd
def calculate_usa_sales(sales_data: pd.DataFrame) -> float:
  return sales_data[sales_data['country'] == 'USA']['sales'].sum() + sales_data[sales_data['country'] == 'USA']['total'].sum()
def calculate_uk_sales(sales_data: pd.DataFrame) -> float:
  return sales_data[sales_data['country'] == 'UK']['sales'].sum() + sales_data[sales_data['country'] == 'UK']['total'].sum()
def calculate_canada_sales(sales_data: pd.DataFrame) -> float:
  return sales_data[sales_data['country'] == 'Canada']['sales'].sum() + sales_data[sales_data['country'] == 'Canada']['total'].sum() * 0.9
sales_data = pd.DataFrame(data)
return calculate_usa_sales(sales_data) + calculate_uk_sales(sales_data) + calculate_canada_sales(sales_data)

