def ancient_sort(numbers):
  l = len(numbers)
  for i in xrange(l):
    for j in xrange(1, l):
      if numbers[j-1] > numbers[j]:
        temp = numbers[j-1]
        numbers[j-1] = numbers[j]
        numbers[j] = temp
  return numbers

