validate_credit_card_number.function_code:
def calculate_luhn_checksum(card_number):
	digits = list(map(int, card_number))
	sum = 0
	for i in range(len(digits)):
		if i % 2 == 0:
			sum += digits[i]
		else:
			alternate_sum = 0
			for j in range(digits[i], 0, -2):
				alternate_sum += j
			sum += alternate_sum
	return sum % 10 == 0

def validate_credit_card_number(card_number):
	return calculate_luhn_checksum(card_number)

