def calculate_total(order_data): 
    grand_total = 0 
    tax_free_total = 0 
    discount_total = 0 
    for item in order_data['items']: 
        if item['is_taxable']: 
            grand_total += item['price'] * item['quantity'] 
        if item['is_discountable']: 
            discount_total += item['discount_amount'] 
        else: 
            tax_free_total += item['price'] * item['quantity'] 
    total_excluding_tax = tax_free_total + discount_total 
    total_including_tax = total_excluding_tax + (grand_total - tax_free_total) * order_data['tax_rate'] / 100 
    return total_including_tax

