import os
import json

 def extract_data(file_path, file_type):
    file_extension = os.path.splitext(file_path)[1].lstrip('.')

    if file_extension != file_type:
        print('Error: file type mismatch')
        return None

    try:
        with open(file_path, 'r') as file:
            content = file.read()

            if file_extension == 'csv':
                rows = content.split('\n')
                if file_type == 'csv_1':
                    data = [row.split(',') for row in rows if row != 'header']
                elif file_type == 'csv_2':
                    data = [row.split(',') for row in rows if row == 'header']
            elif file_extension == 'json':
                data = json.loads(content)
                if file_type == 'json_1':
                    data = data['data']
                elif file_type == 'json_2':
                    data = data['other_data']

            return json.dumps(data)
    except Exception as e:
        print(f'Error: {str(e)}')
        return None



 def save_data(data, file_path):
    try:
        with open(file_path, 'w') as file:
            file.write(data)
        return True
    except Exception as e:
        print(f'Error: {str(e)}')
        return False


def process_data(file_path, file_type, data_folder):
    file_name = os.path.basename(file_path)
    return save_data(extract_data(file_path, file_type), data_folder + '/' + file_type + '/' + file_name)

