def calculate_statistics(file_path):
  try:
    with open(file_path, 'r') as file:
      contents = file.read()
  except FileNotFoundError:
    print('File not found')
    return

  if not contents:
    print('File is empty')
    return

  lines = contents.split('\n')
  total_items = len(lines)
  numbers = [float(num) for num in lines if num.replace('.', '', 1).isdigit()]

  if not numbers:
    print('No numbers found')
    return

  avg = sum(numbers) / len(numbers)
  max_val = max(numbers)
  min_val = min(numbers)

  return {'avg': avg, 'max_val': max_val, 'min_val': min_val, 'total_items': total_items}

