import json
import pandas as pd
from datetime import datetime
from typing import Dict, List

def load_json_data(file_name: str) -> Dict:
    with open(file_name, 'r') as f:
        return json.load(f)

def calculate_total_expenses(data: Dict, department: str) -> Dict[str, float]:
    total_expenses = {}
    for item in data:
        if department in item['department']:
            total_expenses[department] = total_expenses.get(department, 0) + item['cost']
    return total_expenses

def filter_non_numeric_cost(data: List) -> List:
    return [item for item in data if isinstance(item['cost'], (int, float))]

def average_cost_per_item(data: List) -> float:
    return sum(item['cost'] for item in data) / len(data)

def calculate_expenses(file_name: str, department: str) -> Dict:
    data = load_json_data(file_name)
    cost_data = filter_non_numeric_cost(data)
    return {'total_expenses': calculate_total_expenses(data, department), 'avg_cost_per_item': average_cost_per_item(cost_data)}

