import pandas as pd
import os
import glob

class CSVFileProcessor:
   def __init__(self, directory_path, prefix):
      self.directory_path = directory_path
      self.prefix = prefix

   def _get_csv_files(self):
      return glob.glob(self.directory_path + "/*.csv")

   def _filter_files_by_prefix(self):
      return [file for file in self._get_csv_files() if file.startswith(self.prefix)]

   def _read_csv_data(self, csv_file):
      try:
         return pd.read_csv(csv_file)
      except Exception as e:
         print(str(e))

   def _merge_dataframes(self, dataframes):
      return pd.concat(dataframes,ignore_index=True)

   def _write_merged_data(self, dataframe):
      dataframe.to_csv('merged_data.csv',index=False)

   def process_csv_files(self):
      csv_files = self._filter_files_by_prefix()
      dataframes = [self._read_csv_data(file) for file in csv_files]
      merged_df = self._merge_dataframes(dataframes)
      merged_df['file_name'] = csv_files[0] # assuming first file name for demo
      self._write_merged_data(merged_df)

if __name__ == '__main__':
   processor = CSVFileProcessor(directory_path='/path/to/csv/files',prefix='prefix_')
   processor.process_csv_files()

