def process_transaction(card_number, transaction_date, amount):
  import hashlib
  hashed_card_number = hashlib.sha256(card_number.encode()).hexdigest()[:8]
  card_type = 'Unknown'
  if hashed_card_number in ['00000001', '00000002', '00000003']:
    card_type = 'Premium'
  elif hashed_card_number in ['00000004', '00000005', '00000006']:
    card_type = 'Standard'
  return {'card_number': hashed_card_number, 'card_type': card_type, 'transaction_date': transaction_date, 'amount': amount}

