def get_total_cost():
    product_prices = {'apple': 1.00, 'banana': 0.50, 'orange': 1.50}
    quantities = {'apple': 5, 'banana': 3, 'orange': 2}
    discounts = {'apple': 0.1, 'banana': 0.2, 'orange': 0.3}
    taxes = 0.2
    total_cost = 0
    for product in product_prices:
        price = product_prices[product] * quantities[product] * (1 - discounts[product])
        total_cost += price * (1 + taxes)
    return total_cost

