import json
from typing import List

def read_file(path: str) -> str:
    with open(path, 'r') as file:
        return file.read()

def split_string(data: str) -> List[str]:
    return data.split('\n')

def process_lines(lines: List[str]) -> List[str]:
    processed_lines = []
    for line in lines:
        if line.startswith('!') or line.startswith('#'):
            processed_lines.append(line)
    return processed_lines

def create_report_data(file_data: str, processed_data: List[str]) -> str:
    report = ''
    for line in file_data.split('\n'):
        if line not in processed_data:
            report += line + '\n'
    return report

def output_processed_data(report_file_path: str, processed_data: List[str]) -> None:
    with open(report_file_path, 'w') as file:
        for line in processed_data:
            file.write(line + '\n')

def create_report(report_file_path: str, report_data: str) -> None:
    with open(report_file_path, 'w') as file:
        file.write(report_data)

def output_data(output_file_path: str, processed_data: List[str]) -> None:
    with open(output_file_path, 'w') as file:
        for line in processed_data:
            file.write(line + '\n')

def process_data(file_path: str, output_file_path: str) -> None:
    file_data = read_file(file_path)
    file_lines = split_string(file_data)
    processed_data = process_lines(file_lines)
    report_data = create_report_data(file_data, processed_data)
    output_processed_data(output_file_path, processed_data)
    create_report(output_file_path.replace('.out', '.report'), report_data)

