class OrderRepository:
    def __init__(self, db_connection):
        self.db_connection = db_connection

    def get_order_details(self, order_id):
        cursor = self.db_connection.cursor()
        sql_query = "SELECT * FROM orders WHERE id = '%s'" % (order_id)
        cursor.execute(sql_query)
        order_details = cursor.fetchone()
        if order_details:
            return order_details
        else:
            return None

    def calculate_order_total(self, order_id):
        order_details = self.get_order_details(order_id)
        if order_details:
            order = Order(order_details[0], order_details[1], order_details[2])
            for order_item in order_details[4]:
                order.add_order_item(OrderItem(order_item[0], order_item[1], order_item[2]))
            return sum(order_item.quantity * order_item.price for order_item in order.order_items)
        else:
            return "Order not found"

