output.function:
def calculate_account_balance(account_number: str, transaction_date: str, account_type: str, interest_rate: float) -> float: 
    from datetime import datetime 
    from models import db, Transaction 
    from sqlalchemy import func 

    transaction_date = datetime.strptime(transaction_date, '%Y-%m-%d') 
    total_investment = db.session.query(func.sum(Transaction.amount)).filter(Transaction.account_number == account_number, Transaction.date <= transaction_date).scalar() 
    transaction = db.session.query(Transaction).filter(Transaction.account_number == account_number, Transaction.date <= transaction_date).order_by(Transaction.date).all() 

    if transaction: 
        for t in transaction: 
            if t.transaction_type == 'deposit': 
                total_investment += t.amount 
            elif t.transaction_type == 'withdrawal': 
                total_investment -= t.amount 
                total_investment += t.amount * interest_rate 
        if account_type == 'savings': 
            total_investment *= 1.05 
    return max(total_investment, 0)

