def load_data(file_paths):
    import csv
    from typing import Dict
    invoice_items: Dict[str, str] = {}
    discounts: Dict[str, str] = {}
    tax_rates: Dict[str, str] = {}
    for file_name, field_mapping in file_paths.items():
        with open(file_name, 'r') as file:
            reader = csv.DictReader(file)
            for row in reader:
                if file_name == 'invoice_items.csv':
                    invoice_items[row[field_mapping['item_id']]] = row
                elif file_name == 'discounts.csv':
                    discounts[row[field_mapping['discount_id']]] = row
                elif file_name == 'tax_rates.csv':
                    tax_rates[row[field_mapping['tax_rate_id']]] = row
    return invoice_items, discounts, tax_rates

output.calculate_total:
def calculate_total(invoice_items, discounts, tax_rates):
    import decimal
    total = decimal.Decimal('0')
    for item in invoice_items.values():
        total += decimal.Decimal(item['price']) * decimal.Decimal(item['quantity'])
    for discount in discounts.values():
        if discount['type'] == 'percent':
            total -= total * decimal.Decimal(discount['amount']) / 100
        if discount['type'] == 'fixed':
            total -= decimal.Decimal(discount['amount'])
    for tax_rate in tax_rates.values():
        if tax_rate['location'] == 'local':
            total += total * decimal.Decimal(tax_rate['rate']) / 100
        if tax_rate['location'] == 'state':
            total += total * decimal.Decimal(tax_rate['rate']) / 100
    return round(total, 2)

