import json
from typing import Dict

def read_data(file_path: str) -> str:
    with open(file_path, 'r') as file:
        return file.read()

def parse_expenses(text: str) -> Dict:
    expenses = {}
    lines = text.split('\n')
    for line in lines:
        if line.startswith('Salary: '):
            expenses['salary'] = line.split(': ')[1]
        elif line.startswith('Rental: '):
            expenses['rent'] = line.split(': ')[1]
        elif line.startswith('Other Expenses: '):
            expenses['other_expenses'] = line.split(': ')[1]
        elif line.startswith('Non-Taxable Expenses: '):
            expenses['non_taxable_expenses'] = line.split(': ')[1]
        else:
            employee, amount = line.split(': ') 
            expenses[employee] = amount
    return expenses

def calculate_total_expenses(expenses: Dict) -> int:
    return int(expenses['salary']) + int(expenses['rent']) + int(expenses['other_expenses']) + int(expenses['non_taxable_expenses'])

def main(file_path: str) -> Dict:
    text = read_data(file_path)
    expenses = parse_expenses(text)
    total_expenses = calculate_total_expenses(expenses)
    return {'total_expenses': total_expenses, 'expenses': expenses}

if __name__ == '__main__':
    file_path = 'data.txt'
    result = main(file_path)
    print(result)
    with open('result.json', 'w') as file:
        json.dump(result, file)

