from statistics import mean
from typing import Iterable, Union

def data_preprocessing(data: Iterable[str]) -> list[float]:
  return [float(x) for x in data if x.replace('.', '', 1).replace('-', '', 1).isdigit()]

def calculate_statistics(data: Union[list[float], float]) -> tuple[float, float, float, float]:
  if isinstance(data, float):
    return float(data), float(data), float(data), float(data)
  return max(data), min(data), sum(data), mean(data)

def main_function(data: list[str]) -> None:
  preprocessed_data = data_preprocessing(data)
  max_value, min_value, sum_value, average_value = calculate_statistics(preprocessed_data)
  print(f'Max value: {max_value}')
  print(f'Min value: {min_value}')
  print(f'Sum value: {sum_value}')
  print(f'Average value: {average_value}')

