def calculate_order_total(customer_id, order_date, order_items, delivery_address, discount, tax_rate):
    if not customer_id:
        raise ValueError('Customer ID is required')
    if not order_date:
        raise ValueError('Order date is required')
    if not order_items:
        raise ValueError('Order items are required')
    if not delivery_address:
        raise ValueError('Delivery address is required')
    if not discount:
        raise ValueError('Discount is required')
    if not tax_rate:
        raise ValueError('Tax rate is required')
    total_cost = 0
    for item in order_items:
        total_cost += item['price'] * item['quantity']
    subtotal = total_cost - discount
    tax_amount = subtotal * tax_rate
    total_cost += tax_amount
    return subtotal + tax_amount

