class SalesTaxCalculator:
    def __init__(self, tax_rate=tax_rate, sales_tax_exemption_threshold=sales_tax_exemption_threshold):
        self.tax_rate = tax_rate
        self.sales_tax_exemption_threshold = sales_tax_exemption_threshold

    def calculate(self, price: float, discount_rate(Optional float) = None):
        if price >= self.sales_tax_exemption_threshold:
            tax_amount = price * self.tax_rate
        else:
            tax_amount = price * self.tax_rate * (1 - discount_rate if discount_rate is not None else 0)
        return price + tax_amount + 2.99

